{
  "name": "temporal-cancel-cleanup",
  "version": "1.0.0",
  "description": "Graceful workflow cancellation with cleanup using Temporal TypeScript SDK",
  "main": "index.js",
  "scripts": {
    "build": "tsc --build",
    "start": "node -r ts-node/register src/start.ts",
    "worker": "ts-node src/worker.ts",
    "client": "ts-node src/client.ts"
  },
  "dependencies": {
    "@temporalio/activity": "^1.11.7",
    "@temporalio/client": "^1.11.7",
    "@temporalio/worker": "^1.11.7",
    "@temporalio/workflow": "^1.11.7"
  },
  "devDependencies": {
    "@types/node": "^20.0.0",
    "ts-node": "^10.9.2",
    "typescript": "^5.4.5"
  }
}

import { heartbeat, sleep, isCancellation } from '@temporalio/activity';

/**
 * Long-running activity that simulates work for ~60 seconds.
 * Heartbeats every ~500ms so cancellation is delivered promptly.
 * When cancelled, the sleep() call will throw CancelledFailure which we rethrow.
 */
export async function doWork(): Promise<void> {
  console.log('[doWork] Starting work loop (~60 seconds)...');
  // Loop for up to 120 iterations × 500ms = ~60 seconds
  for (let i = 0; i < 120; i++) {
    heartbeat({ iteration: i, message: 'working' });
    try {
      await sleep(500);
    } catch (err) {
      if (isCancellation(err)) {
        console.log(`[doWork] Cancellation received at iteration ${i}, rethrowing.`);
        throw err;
      }
      throw err;
    }
    if (i % 10 === 0) {
      console.log(`[doWork] Iteration ${i}/120`);
    }
  }
  console.log('[doWork] Work loop completed normally.');
}

/**
 * Compensation activity that runs even when the workflow is being cancelled.
 * Returns the literal string "cleanup-done".
 */
export async function cleanup(): Promise<string> {
  console.log('[cleanup] Running cleanup compensation...');
  const result = 'cleanup-done';
  console.log(`[cleanup] Cleanup complete, returning: ${result}`);
  return result;
}

import {
  proxyActivities,
  CancellationScope,
  isCancellation,
  ActivityCancellationType,
  log,
} from '@temporalio/workflow';

// Import type only — workflow sandbox cannot import activity implementation
import type * as activities from './activities';

/**
 * Proxy for doWork:
 *  - startToCloseTimeout longer than the ~60s work loop
 *  - heartbeatTimeout short so cancellation is detected quickly
 *  - TRY_CANCEL so the workflow doesn't have to wait for doWork to
 *    acknowledge cancellation before proceeding to the cleanup branch
 */
const { doWork } = proxyActivities<typeof activities>({
  startToCloseTimeout: '120 seconds',
  heartbeatTimeout: '10 seconds',
  cancellationType: ActivityCancellationType.TRY_CANCEL,
});

/**
 * Proxy for cleanup:
 *  - Runs inside a nonCancellable scope so it cannot be cancelled itself.
 *  - No cancellationType override needed.
 */
const { cleanup } = proxyActivities<typeof activities>({
  startToCloseTimeout: '30 seconds',
});

/**
 * CancellableWorkflow
 *
 * Pattern:
 *  1. Run doWork inside a cancellable scope.
 *  2. If the workflow is cancelled, isCancellation(err) will be true.
 *  3. Run cleanup inside a nonCancellable scope so it survives the
 *     surrounding cancellation.
 *  4. Rethrow the original CancelledFailure so Temporal records the
 *     execution with status CANCELED.
 */
export async function CancellableWorkflow(): Promise<void> {
  log.info('CancellableWorkflow started');

  try {
    await CancellationScope.cancellable(async () => {
      await doWork();
    });
  } catch (err) {
    if (isCancellation(err)) {
      log.info('Cancellation detected — running cleanup in nonCancellable scope');

      // Shield cleanup from the parent scope's cancellation so it always runs
      await CancellationScope.nonCancellable(async () => {
        await cleanup();
      });

      log.info('Cleanup completed — rethrowing cancellation');
      // Rethrow so the workflow execution is recorded as CANCELED
      throw err;
    }
    // Unexpected error — propagate as-is
    throw err;
  }

  log.info('CancellableWorkflow completed normally (no cancellation)');
}

import { NativeConnection, Worker } from '@temporalio/worker';
import * as activities from './activities';
import path from 'path';

const TASK_QUEUE = 'cancel-cleanup-ts';

async function main(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!address) throw new Error('TEMPORAL_ADDRESS environment variable is required');
  if (!apiKey) throw new Error('TEMPORAL_API_KEY environment variable is required');
  if (!namespace) throw new Error('TEMPORAL_NAMESPACE environment variable is required');

  console.log(`[worker] Connecting to Temporal Cloud at ${address} (namespace: ${namespace})`);

  // NativeConnection for the Worker — connects with TLS + API key
  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: TASK_QUEUE,
    // Point at the compiled workflow bundle (workflow sandbox requires a path)
    workflowsPath: path.resolve(__dirname, './workflows'),
    activities,
  });

  console.log(`[worker] Worker created, polling task queue: ${TASK_QUEUE}`);
  // Signal the parent process (if any) that we are ready
  if (process.send) {
    process.send('ready');
  }
  // Also write to stdout so the orchestrator can detect readiness via output
  process.stdout.write('WORKER_READY\n');

  // Run until the process is interrupted
  await worker.run();
}

main().catch((err) => {
  console.error('[worker] Fatal error:', err);
  process.exit(1);
});

import { Connection, Client, WorkflowFailedError } from '@temporalio/client';
import { isCancellation } from '@temporalio/workflow';
import { CancellableWorkflow } from './workflows';

const TASK_QUEUE = 'cancel-cleanup-ts';

async function main(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address) throw new Error('TEMPORAL_ADDRESS environment variable is required');
  if (!apiKey) throw new Error('TEMPORAL_API_KEY environment variable is required');
  if (!namespace) throw new Error('TEMPORAL_NAMESPACE environment variable is required');
  if (!runId) throw new Error('ZEALT_RUN_ID environment variable is required');

  const workflowId = `cancel-wf-${runId}`;

  console.log(`[client] Connecting to Temporal Cloud at ${address} (namespace: ${namespace})`);

  // Client connection — uses TLS + API key
  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  console.log(`[client] Starting workflow: ${workflowId} on task queue: ${TASK_QUEUE}`);

  const handle = await client.workflow.start(CancellableWorkflow, {
    taskQueue: TASK_QUEUE,
    workflowId,
  });

  console.log(`[client] Workflow started: ${handle.workflowId} (runId: ${handle.firstExecutionRunId})`);
  console.log('[client] Waiting 3 seconds before cancelling...');

  // Wait ~3 seconds to let the workflow (and doWork activity) get going
  await new Promise<void>((resolve) => setTimeout(resolve, 3000));

  console.log('[client] Sending cancellation request to workflow...');
  await handle.cancel();
  console.log('[client] Cancellation sent. Awaiting workflow result...');

  // Await the result — it WILL throw because the workflow ends as CANCELED
  try {
    await handle.result();
    // If we reach here, the workflow completed without cancellation (unexpected)
    console.error('[client] ERROR: Workflow completed without cancellation — unexpected!');
    process.exit(1);
  } catch (err) {
    if (err instanceof WorkflowFailedError && isCancellation(err.cause)) {
      // This is the expected path: the workflow was cancelled successfully
      // and cleanup ran (we can confirm by checking the event history, but
      // the acceptance criterion is the stdout line below)
      console.log('cleanup-done observed');
    } else {
      console.error('[client] Unexpected error awaiting workflow result:', err);
      throw err;
    }
  }

  await connection.close();
  console.log('[client] Done.');
}

main().catch((err) => {
  console.error('[client] Fatal error:', err);
  process.exit(1);
});

/**
 * Orchestrator: starts the Worker, waits for it to be ready, then runs the
 * Client. Exits with code 0 after the client observes the cancellation.
 *
 * Run via: npm start  (node -r ts-node/register src/start.ts)
 */

import { spawn, ChildProcess } from 'child_process';
import path from 'path';

const WORKER_READY_SIGNAL = 'WORKER_READY';
// Maximum time to wait for the worker to print WORKER_READY
const WORKER_READY_TIMEOUT_MS = 60_000;

function spawnTsNode(script: string, label: string): ChildProcess {
  const tsNodeBin = path.resolve(__dirname, '..', 'node_modules', '.bin', 'ts-node');
  const child = spawn(process.execPath, ['-r', 'ts-node/register', script], {
    env: process.env,
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  child.stdout!.on('data', (data: Buffer) => {
    const lines = data.toString().split('\n');
    for (const line of lines) {
      if (line.trim()) console.log(`[${label}] ${line.trim()}`);
    }
  });
  child.stderr!.on('data', (data: Buffer) => {
    const lines = data.toString().split('\n');
    for (const line of lines) {
      if (line.trim()) console.error(`[${label}:err] ${line.trim()}`);
    }
  });

  return child;
}

async function waitForWorkerReady(worker: ChildProcess): Promise<void> {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      reject(new Error(`Worker did not become ready within ${WORKER_READY_TIMEOUT_MS}ms`));
    }, WORKER_READY_TIMEOUT_MS);

    let buffer = '';
    worker.stdout!.on('data', (data: Buffer) => {
      buffer += data.toString();
      if (buffer.includes(WORKER_READY_SIGNAL)) {
        clearTimeout(timer);
        resolve();
      }
    });

    worker.on('exit', (code) => {
      clearTimeout(timer);
      reject(new Error(`Worker exited prematurely with code ${code}`));
    });
  });
}

function runClient(): Promise<number> {
  return new Promise((resolve, reject) => {
    const clientScript = path.resolve(__dirname, 'client.ts');
    const client = spawn(process.execPath, ['-r', 'ts-node/register', clientScript], {
      env: process.env,
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    client.stdout!.on('data', (data: Buffer) => {
      const lines = data.toString().split('\n');
      for (const line of lines) {
        if (line.trim()) {
          // Echo client stdout directly (required for the acceptance criterion
          // "cleanup-done observed" to appear in the combined stdout)
          process.stdout.write(line.trim() + '\n');
        }
      }
    });
    client.stderr!.on('data', (data: Buffer) => {
      const lines = data.toString().split('\n');
      for (const line of lines) {
        if (line.trim()) console.error(`[client:err] ${line.trim()}`);
      }
    });

    client.on('exit', (code) => {
      resolve(code ?? 0);
    });
    client.on('error', reject);
  });
}

async function main(): Promise<void> {
  const workerScript = path.resolve(__dirname, 'worker.ts');

  console.log('[start] Spawning worker process...');
  const worker = spawnTsNode(workerScript, 'worker');

  // Also listen to the raw stdout for the WORKER_READY signal while we still
  // forward it line-by-line to our console via the handler above.
  let workerReadyResolve: (() => void) | null = null;
  let workerReadyBuffer = '';
  const workerReadyPromise = new Promise<void>((resolve, reject) => {
    workerReadyResolve = resolve;
    const timer = setTimeout(() => {
      reject(new Error(`Worker did not emit '${WORKER_READY_SIGNAL}' within ${WORKER_READY_TIMEOUT_MS}ms`));
    }, WORKER_READY_TIMEOUT_MS);

    worker.stdout!.on('data', (chunk: Buffer) => {
      workerReadyBuffer += chunk.toString();
      if (workerReadyBuffer.includes(WORKER_READY_SIGNAL)) {
        clearTimeout(timer);
        resolve();
      }
    });

    worker.on('exit', (code) => {
      clearTimeout(timer);
      if (!workerReadyBuffer.includes(WORKER_READY_SIGNAL)) {
        reject(new Error(`Worker exited (code ${code}) before becoming ready`));
      }
    });
  });

  // Give worker stdout events a chance to fire in the right order by removing
  // the duplicate listener added above (we attached two data handlers; Node
  // EventEmitter delivers to all; this is fine — both receive every chunk).

  try {
    console.log('[start] Waiting for worker to be ready...');
    await workerReadyPromise;
    console.log('[start] Worker is ready. Starting client...');
  } catch (err) {
    console.error('[start] Worker failed to become ready:', err);
    worker.kill('SIGTERM');
    process.exit(1);
  }

  let clientExitCode = 1;
  try {
    clientExitCode = await runClient();
  } catch (err) {
    console.error('[start] Client process error:', err);
  }

  console.log('[start] Client finished with exit code:', clientExitCode);

  // Gracefully terminate the worker
  console.log('[start] Stopping worker...');
  worker.kill('SIGTERM');
  await new Promise<void>((resolve) => {
    worker.on('exit', () => resolve());
    // Force-kill after 10s if it doesn't exit cleanly
    setTimeout(() => {
      worker.kill('SIGKILL');
      resolve();
    }, 10_000);
  });

  console.log('[start] All processes exited.');

  // Exit with 0 if the client succeeded, non-zero otherwise
  process.exit(clientExitCode === 0 ? 0 : clientExitCode);
}

main().catch((err) => {
  console.error('[start] Unhandled error:', err);
  process.exit(1);
});

